    // Utility to read entire file as String
    private String readFile(File f) throws IOException {
        StringBuilder sb = new StringBuilder();
        try (Reader r = new BufferedReader(new InputStreamReader(new FileInputStream(f), StandardCharsets.UTF_8))) {
            char[] buf = new char[1024];
            int n;
            while ((n = r.read(buf)) != -1) {
                sb.append(buf, 0, n);
            }
        }
        return sb.toString();
    }

    @Test
    @DisplayName("TC01: wrap(CharSequence) with short text under maxWidth avoids any wrapping (branch false for tooLong)")
    public void test_TC01() {
        // input shorter than default 80 cols, so tooLong never true -> no wrap
        String text = "Hello world";
        String result = WordWrap.from(text).wrap();
        assertEquals("Hello world", result);
    }

    @Test
    @DisplayName("TC02: wrap(CharSequence) with newline in input preserves line boundary and does not wrap (branch ch=='\\n')")
    public void test_TC02() {
        // Contains newline, triggers explicit newline handling branch
        String text = "A line\nB line";
        String result = WordWrap.from(text).wrap();
        assertEquals("A line\nB line", result);
    }

    @Test
    @DisplayName("TC03: wrap(CharSequence) with a long unbroken word and breakWords=true inserts hyphens and wraps")
    public void test_TC03() {
        // Unbroken word length 11 > maxWidth=5, breakWords true triggers hyphenated splits
        String text = "abcdefghijk";
        String result = WordWrap.from(text).maxWidth(5).wrap();
        // expect splits of 3 chars + hyphen then newline repeatedly
        String expected = "abc-\ndef-\nghij-\nk";
        assertEquals(expected, result);
    }

    @Test
    @DisplayName("TC04: wrap(CharSequence) with long unbroken word and breakWords=false sets broken flag rather than hyphenating")
    public void test_TC04() {
        // Unbroken word length 8 > maxWidth=3, breakWords false triggers broken flag and no hyphens
        String text = "abcdefgh";
        String result = WordWrap.from(text).maxWidth(3).breakWords(false).wrap();
        // intended behavior: no hyphen splitting, entire word remains on single line
        assertEquals("abcdefgh", result);
    }

    @Test
    @DisplayName("TC05: wrap(CharSequence) with inserted extraWordChars treats punctuation as word character avoiding break at punctuation")
    public void test_TC05() {
        // Include '!' as extra word char so punctuation isn't boundary -> hyphenation occurs after a!b
        String text = "a!bcdefg";
        String result = WordWrap.from(text).maxWidth(4).includeExtraWordChars("!").wrap();
        // Expect first line includes "a!b-" if hyphen inserted after fitting up to width
        // verify hyphenation point
        assertEquals(true, result.contains("a!b-"));
    }

